INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-6f0ba476-moex-00061', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於社團法人總會之決議，下列敘述何者錯誤？', '["法律規定一定人數以上之社員出席，為該法律行為之成立要件", "欠缺一定人數以上之社員出席，則該決議方法當然違法", "該決議必先符合成立要件，始須探究該決議是否有得撤銷或無效事由", "該決議係社員基於平行與協同之意思表示"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00062', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲住進養老院後，將其所有之A屋贈與其女乙，約定若甲有朝一日不願 繼續住養老院，乙應將受贈取得之A屋返還於甲。嗣後，甲不適應而遷 出養老院，下列敘述何者正確？', '["甲乙約定純粹繫於甲之意志，將致乙之法律地位不穩定，故該約定無效", "甲乙間之贈與契約效力未定，甲遷出養老院表示無意贈與，該契約自始 無效", "乙受贈A屋並取得所有權有效，甲遷出養老院停止條件成就，贈與契 約與所有權移轉皆自始無效", "乙受贈A屋並取得所有權有效，甲遷出養老院解除條件成就，贈與契 約與所有權移轉自條件成就時，失其效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00063', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於消滅時效之敘述，何者錯誤？', '["消滅時效有時效中斷或不完成，致時效重行起算或延長", "消滅時效完成後，債務人須提出時效抗辯，法院始得加以裁判", "凡請求權，無論其發生原因，均為消滅時效之客體", "在同一原因事實，發生二個以上契約上請求權，而有特別規定之短期 時效者，自應優先適用該短期時效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00064', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者屬於處分行為？', '["自用車之買賣契約", "房屋之拆除", "動產物權之讓與合意", "房屋之租賃契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00065', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者意思表示已經生效？', '["未成年人甲與成年人乙之越野車買賣契約，經乙催告甲之法定代理人 丙於一個月內確答是否同意，丙於期限內沉默未為任何表示", "成年人乙心愛之貓咪走失，乙完成張貼尋貓懸賞廣告", "出租人甲欲終止與乙之租賃契約，甲將終止契約之意思表示以存證信 函寄出時", "甲前往乙藝廊，欲購買乙藝廊中A畫，未遇到藝廊經營之主人乙，而 是湊巧遇到丙，丙為乙之配偶，當日僅是路過順道進入乙藝廊，甲將 其欲購買A畫之意願與價金告知丙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00066', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲於民國（下同）112 年7 月 1 日央請乙向丙借款作為購買 A 車之用， 乙遂於同日以自己之名義向丙借貸新臺幣（下同）500萬元，約定112年', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00067', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '月 31 日為該筆借款之清償期。乙從丙處取得該款項後，交付甲用以 向丁購買 A 車。嗣後，甲於 112 年 9 月 28 日期前對丙清償上述款項。 之後，丙於112年10月1日將上述500萬元之借款債權出賣於辛。該債 權之買賣契約效力為何？', '["依民法第246條有關標的不能規定，該債權之買賣契約無效", "依民法第246條有關標的不能規定，該債權之買賣契約有效", "依民法第350條有關權利瑕疵擔保規定，該債權之買賣契約無效", "依民法第350條有關權利瑕疵擔保規定，該債權之買賣契約有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00068', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '機師甲與航空公司乙訂立聘僱契約，約定最低服務年限為15年，若甲違 約離職，應賠償訓練費用及新臺幣（下同）300萬元之違約金，並由丙擔 任保證人。甲任職滿10年時離職，因丙財力雄厚，乙遂向丙請求負保證 人責任。依實務見解，下列敘述何者正確？', '["丙之保證契約，雖未定期間，然依民法規定，保證契約自成立之日起， 有效期間為3年，而甲已任職滿10年，故保證契約失效，丙不負賠償 責任", "丙於乙未就甲之財產強制執行而無效果前，對於乙得拒絕清償", "甲離職時，乙尚未給付甲應得之績效獎金10萬元。由於績效獎金具有 一身專屬性，丙不得主張抵銷", "丙得主張賠償金額，以賠償事故發生時，受僱人當年可得報酬之總額 為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00069', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲基於買賣契約，對乙有新臺幣（下同）20萬元之價金債權，若甲將該 債權出賣於丙，並將該債權讓與丙。下列敘述何者正確？', '["甲應將債權讓與一事通知乙，否則甲與丙之債權讓與無效", "甲與丙訂立買賣債權之契約時，債權即移轉於丙", "甲應擔保債務人乙之支付能力", "若甲未通知乙，已將債權讓與丙，乙仍對甲支付20萬元價金，則乙之 債務消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00070', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲將一隻狼狗出租於乙公司作為工廠之守護，平日由乙公司職員丙負責 狼狗之管束。因丙對狼狗之管束未盡相當之注意，致狼狗咬傷送信之郵 差丁。關於何者應負損害賠償之責任，下列敘述何者正確？', '["甲是間接占有人，應負損害賠償責任", "乙是直接占有人，應負損害賠償責任", "丙是占有輔助人，不負損害賠償責任", "甲乙丙對丁均不須負損害賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
